# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from PIL import Image
import io
import base64
import os

s3 = boto3.client('s3', aws_access_key_id=os.environ['AWS_ACCESS_KEY_ID'],
                                    aws_secret_access_key=os.environ['AWS_SECRET_ACCESS_KEY'])

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    
    width, height = 320, 180 # thumbnails are 160x90 but we need to crop
    left = (driver.execute_script("return document.body.offsetWidth") - width) / 2.0
    top = (driver.execute_script("return document.body.parentNode.scrollTop") + 
           (driver.execute_script("return document.body.offsetWidth") - width) / 2.0)
    
    driver.set_window_size(width, height)
    driver.set_window_position(left, top)

    screenshot = driver.get_screenshot_as_png()

    # Save it to s3
    bucket_name = 'your-bucket-name'
    file_object = io.BytesIO(screenshot)
    image_name = url.split('/')[-1] + '.png'
    s3.put_object(Body=file_object.read(), Bucket=bucket_name, Key=image_name)

    driver.quit()

    # Save thumbnail
    img = Image.open(io.BytesIO(screenshot))
    left = (img.size[0] - width) / 2.0
    top = (img.size[1] - height) / 2.0
    right = left + width
    bottom = top + height

    img = img.crop((left, top, right, bottom))

    thumbnail_name = url.split('/')[-1] + '_thumbnail.png'
    with io.BytesIO() as buffer:
        img.save(buffer, 'PNG')
        s3.put_object(Body=buffer.getvalue(), Bucket=bucket_name, Key=thumbnail_name)

def lambda_handler(event):
    if 'url' in event['queryStringParameters']:
        url = event['queryStringParameters']['url']
        take_screenshot(url)
    else:
        return {
            'statusCode': 400,
            'statusMessage': 'No URL provided'
        }
    
    bucket_name = 'your-bucket-name'
    thumbnail_name = url.split('/')[-1] + '_thumbnail.png'

    # Generate signed URL for the thumbnail
    s3_url = f'https://{bucket_name}.s3.amazonaws.com/{thumbnail_name}'
    return {
        "statusCode": 200,
        "body": {"image_url": s3_url}
    }